commit dd273d359e45ab69398ac0dc41206d5f1a9371bf
Author: Guo Yejun <yejun.guo@intel.com>
Date:   Wed Jun 10 13:36:11 2020 +0800

    dnn_backend_native: check operand index

    it fixed the issue in https://trac.ffmpeg.org/ticket/8716
    (cherry-pick from 0b3bd001ac1745d9d008a2d195817df57d7d1d14)
    Signed-off-by: Guo, Yejun <yejun.guo@intel.com>

diff --git a/libavfilter/dnn/dnn_backend_native.c b/libavfilter/dnn/dnn_backend_native.c
index 12695a0232..35236fc66f 100644
--- a/libavfilter/dnn/dnn_backend_native.c
+++ b/libavfilter/dnn/dnn_backend_native.c
@@ -119,173 +119,177 @@ DNNModel *ff_dnn_load_model_native(const char *model_filename)
     char header_expected[] = "FFMPEGDNNNATIVE";
     char *buf;
     size_t size;
     int version, header_size, major_version_expected = 1;
     ConvolutionalNetwork *network = NULL;
     AVIOContext *model_file_context;
     int file_size, dnn_size, parsed_size;
     int32_t layer;
     DNNLayerType layer_type;

     if (avio_open(&model_file_context, model_filename, AVIO_FLAG_READ) < 0){
         return NULL;
     }
     file_size = avio_size(model_file_context);

     model = av_mallocz(sizeof(DNNModel));
     if (!model){
         goto fail;
     }

     /**
      * check file header with string and version
      */
     size = sizeof(header_expected);
     buf = av_malloc(size);
     if (!buf) {
         goto fail;
     }

     // size - 1 to skip the ending '\0' which is not saved in file
     avio_get_str(model_file_context, size - 1, buf, size);
     dnn_size = size - 1;
     if (strncmp(buf, header_expected, size) != 0) {
         av_freep(&buf);
         goto fail;
     }
     av_freep(&buf);

     version = (int32_t)avio_rl32(model_file_context);
     dnn_size += 4;
     if (version != major_version_expected) {
         goto fail;
     }

     // currently no need to check minor version
     version = (int32_t)avio_rl32(model_file_context);
     dnn_size += 4;
     header_size = dnn_size;

     network =

